package com.flowledger.organization.service;
import com.flowledger.common.exception.ResourceNotFoundException;import com.flowledger.common.security.SecurityUtils;import com.flowledger.organization.dto.*;import com.flowledger.organization.entity.Organization;import com.flowledger.organization.mapper.OrganizationMapper;import com.flowledger.organization.repository.OrganizationRepository;import com.flowledger.storage.StorageService;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.web.multipart.MultipartFile;import java.util.UUID;
@Service public class OrganizationService {private final OrganizationRepository repo;private final OrganizationMapper mapper;private final StorageService storage;public OrganizationService(OrganizationRepository r,OrganizationMapper m,StorageService s){repo=r;mapper=m;storage=s;}public OrganizationResponse current(){return mapper.toResponse(get(SecurityUtils.currentOrganizationId()));}@Transactional public OrganizationResponse update(UUID id,UpdateOrganizationRequest r){Organization o=get(id);mapper.update(r,o);return mapper.toResponse(o);}@Transactional public String uploadLogo(UUID id,MultipartFile f){Organization o=get(id);String key="organizations/"+id+"/logo/"+UUID.randomUUID()+"-"+f.getOriginalFilename();storage.store(key,f);o.setLogoObjectKey(key);return key;}private Organization get(UUID id){return repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Organization not found"));}}
